def balanced(s):
    """Return True if parentheses in string are balanced, False otherwise."""
    stack = []
    for char in s:
        if char == '(':
            stack.append(char)
        elif char == ')':
            if not stack:
                return False  # Edge case: unmatched closing parenthesis
            stack.pop()
    return not stack  # An empty stack means parentheses are balanced
